class Solution:
    def maxPossibleScore(self, start, d):
        starts = sorted(start)
        n = len(starts)
        lo, hi = 0, starts[-1] + d - starts[0]
        def feasible(g):
            prev = starts[0]
            for i in range(1, n):
                nxt = max(starts[i], prev + g)
                if nxt > starts[i] + d:
                    return False
                prev = nxt
            return True
        ans = 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

