solutions.javascript:
var maxPossibleScore = function(start, d) {
    const starts = start.slice().sort((a, b) => a - b);
    const n = starts.length;

    const feasible = (g) => {
        let prev = starts[0];
        for (let i = 1; i < n; i++) {
            const nxt = Math.max(starts[i], prev + g);
            if (nxt > starts[i] + d) return false;
            prev = nxt;
        }
        return true;
    };

    let lo = 0, hi = starts[n - 1] + d - starts[0];
    let ans = 0;
    while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (feasible(mid)) {
            ans = mid;
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return ans;
};
